pub fn is_executed<DB: Database>(db: &mut DB, contract: Option<Address>, call_id: u64, index: u64) -> Result<bool, SchedulerError> {
    ...
    if index < 256 {
        let slot = executed_bitmap_slot(call_id);
        let bitmap = db.storage(contract, slot)?;
        Ok((bitmap & (U256::from(1) << index)) != U256::ZERO)
    } else {
        let adjusted_index = index - 256;
        let bucket = adjusted_index / 256;
        let bit_position = adjusted_index % 256;
        let slot = executed_bitmap_overflow_slot(call_id, bucket);
        let bitmap = db.storage(contract, slot)?;
        Ok((bitmap & (U256::from(1) << bit_position)) != U256::ZERO)
    }
}

pub fn executed_bitmap_overflow_slot(call_id: u64, bucket: u64) -> U256 {
    let mut key_data = [0u8; 64];
    key_data[24..32].copy_from_slice(&call_id.to_be_bytes());
    key_data[56..64].copy_from_slice(&bucket.to_be_bytes());
    let key = keccak256(&key_data);
    let mut slot_data = [0u8; 64];
    slot_data[0..32].copy_from_slice(key.as_slice());
    slot_data[32..64].copy_from_slice(&SCHEDULER_EXECUTED_OVERFLOW_SLOT.to_be_bytes::<32>());
    U256::from_be_slice(keccak256(&slot_data).as_slice())
}
